  function lang(){ const l=localStorage.getItem('lang')||document.documentElement.lang||'fa'; return ['fa','en','hr'].includes(l)?l:'fa'; }
  function tr(k){ return (UI[lang()]&&UI[lang()][k])||UI.en[k]||k; }
  function esc(v){ return String(v==null?'':v).replace(/[&<>"']/g, ch=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch])); }
  function nl(v){ return esc(v).replace(/\n/g,'<br>'); }
  function uid(){ return session&&session.user&&session.user.id; }
  function isAdmin(){ return (session?.user?.email||'').toLowerCase()===ADMIN_EMAIL; }
  function lessonList(){ return DATA.lessons[lang()]||DATA.lessons.fa||[]; }
  function examList(){ return DATA.exam[lang()]||DATA.exam.fa||[]; }
  function lessonByCode(code){ return lessonList().find(x=>x.code===code) || (DATA.lessons.fa||[]).find(x=>x.code===code); }
  function completedSet(){ return new Set((progress||[]).filter(p=>p.completed).map(p=>p.lesson_code)); }
  function isUnlocked(lesson){ const list=lessonList(); if(lesson.order===1) return true; const prev=list.find(x=>x.order===lesson.order-1); return prev && completedSet().has(prev.code); }
  function allCompleted(){ const set=completedSet(); return lessonList().every(l=>set.has(l.code)); }
  function noteFor(code, idx){ return (notes||[]).find(n=>n.lesson_code===code && Number(n.note_index)===idx)?.note_text || ''; }
  function assignmentFor(code){ return (assignments||[]).find(a=>a.lesson_code===code) || null; }
  function assignmentText(code){ return assignmentFor(code)?.assignment_text || ''; }
  function showStatus(msg, bad){ const el=document.querySelector('#schoolStatus'); if(el){ el.textContent=msg||''; el.style.color=bad?'#b00020':'#0a6b2b'; } }
  function schoolTerms(){ return DATA.terms[lang()]||DATA.terms.fa||DATA.terms.en||{}; }

  function loadScript(src){ return new Promise((res,rej)=>{ const s=document.createElement('script'); s.src=src; s.onload=res; s.onerror=rej; document.head.appendChild(s); }); }
  async function ensureSupabase(){
    if(sb) return sb;
    if(!window.supabase?.createClient){ await loadScript('https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2'); }
    sb=window.supabase.createClient(SUPABASE_URL, SUPABASE_KEY);
    const {data}=await sb.auth.getSession(); session=data?.session||null;
    sb.auth.onAuthStateChange((_event, sess)=>{ session=sess; refreshSchool(); });
    return sb;
  }

